import React from "react";

function Form({ data, setData }) {
  const handleChange = (e) => {
    setData({
      ...data,
      [e.target.name]: e.target.value
    });
  };

  return (
    <div style={{ width: "50%" }}>
      <h2>Form</h2>

      <input
        type="text"
        name="name"
        placeholder="Enter Name"
        value={data.name}
        onChange={handleChange}
      />

      <br /><br />

      <input
        type="email"
        name="email"
        placeholder="Enter Email"
        value={data.email}
        onChange={handleChange}
      />

      <br /><br />

      <input
        type="text"
        name="phone"
        placeholder="Enter Phone"
        value={data.phone}
        onChange={handleChange}
      />

      <br /><br />

      <textarea
        name="skills"
        placeholder="Enter Skills"
        value={data.skills}
        onChange={handleChange}
      />
    </div>
  );
}

export default Form;
